"use client";

/**
 * Positionswolken — divergierende Likert-Verteilung je Thema. Schwesteransicht
 * zum Positionsband: Statt eines einzelnen Balkens fällt jede Argument-Bewertung
 * in eine von fünf Stufen (Nein · eher Nein · neutral · eher Ja · Ja). Die Stufen
 * werden als Pill-Segmente auf einer dezenten Schiene gestapelt und von der
 * neutralen Mitte aus ausgewogen — die neutrale Stufe sitzt mittig auf der Achse,
 * Ablehnung wächst nach links, Zustimmung nach rechts.
 *
 * Die Zeilen sind nach Netto-Zustimmung sortiert (Leaderboard). Das Badge rechts
 * verdichtet alles auf eine Kennzahl: Netto-Score = Zustimmung − Ablehnung in
 * Prozentpunkten (neutral zählt nicht).
 *
 * Skala für ALLE Themen identisch (sonst nicht vergleichbar): gleiche
 * Stufengrenzen, gleiche Mitte, gemeinsame Schiene.
 *
 * Achs-Mapping: c = (PRO ? +1 : −1) · (preference − 50) / 50 ∈ [−1, 1]
 * (−1 = Nein, 0 = neutral, +1 = Ja) — identisch zu Positionsband/Panorama.
 */
import { useMemo } from "react";
import type { TaxonomyNode, TaxonomyArgument } from "@/types/ballots";
import { Card, CardContent } from "@/components/ui/card";

type T = (key: string) => string;

// Fünf Likert-Stufen, von Ablehnung (links) zu Zustimmung (rechts).
const CATS = [
  { key: "no", label: "panoramaNo", color: "#8a4a37" }, // Nein (dunkel terra)
  { key: "ratherNo", label: "cloudRatherNo", color: "#cd8a6a" }, // eher Nein
  { key: "neutral", label: "neutral", color: "#bcbcbc" }, // neutral (grau)
  { key: "ratherYes", label: "cloudRatherYes", color: "#9cc8ae" }, // eher Ja
  { key: "yes", label: "panoramaYes", color: "#4e9b76" }, // Ja (grün)
] as const;

// Volltöne fürs Netto-Score-Badge.
const POS = { bg: "rgba(78, 155, 118, 0.14)", fg: "rgb(47, 122, 89)" };
const NEG = { bg: "rgba(178, 116, 92, 0.16)", fg: "rgb(166, 86, 56)" };
const ZERO = { bg: "rgba(0,0,0,0.05)", fg: "var(--muted-foreground)" };

/* ---------- Achsen-Geometrie (viewBox-Breite 600) ---------- */
const VW = 600;
const PAD = 10;
const X0 = PAD;
const X1 = VW - PAD;
const XC = (X0 + X1) / 2; // neutrale Mitte
const HALF = (X1 - X0) / 2; // entspricht Anteil 1.0 je Seite
const BARH = 22;
const BAR_Y = 4;
const BAR_H = 14;
const TRACK_Y = 3;
const TRACK_H = 16;
const GAP = 2; // Lücke zwischen Pill-Segmenten (px)

// c ∈ [−1,1] → Likert-Stufe 0…4 (gleich breite Fünftel).
function categorize(c: number): number {
  if (c < -0.6) return 0;
  if (c < -0.2) return 1;
  if (c <= 0.2) return 2;
  if (c <= 0.6) return 3;
  return 4;
}

// −/+ mit echtem Minuszeichen, z. B. „+46", „−28". v ∈ [−1,1] → Prozentpunkte.
function signed(v: number): string {
  const n = Math.round(v * 100);
  if (n > 0) return `+${n}`;
  if (n < 0) return `−${Math.abs(n)}`;
  return "0";
}

/* ---------- distinct Bewertungen eines Teilbaums ---------- */
function collectContribs(node: TaxonomyNode): number[] {
  const seen = new Map<string, number>();
  const walk = (n: TaxonomyNode) => {
    for (const a of (n.arguments ?? []) as TaxonomyArgument[]) {
      if (a.viewerPreference == null || seen.has(a.uri)) continue;
      const sign = a.type === "PRO" ? 1 : -1;
      seen.set(a.uri, (sign * (a.viewerPreference - 50)) / 50);
    }
    for (const c of n.children ?? []) walk(c);
  };
  walk(node);
  return [...seen.values()];
}

type Seg = { i: number; x: number; w: number };
type Row = { node: TaxonomyNode; n: number; mean: number; segs: Seg[] };

export function PositionCloud({ nodes, t }: { nodes: TaxonomyNode[]; t: T }) {
  const rows = useMemo<Row[]>(() => {
    const built = nodes.map((node) => {
      const cs = collectContribs(node);
      const n = cs.length;
      const counts = [0, 0, 0, 0, 0];
      for (const c of cs) counts[categorize(c)]++;
      const f = counts.map((k) => (n ? k / n : 0));
      // Kennzahl: Mittelwert aller Bewertungen (c ∈ [−1,1] → Prozentpunkte).
      const mean = n ? cs.reduce((a, b) => a + b, 0) / n : 0;
      // Divergierend: neutrale Stufe mittig auf der Achse, Rest links/rechts.
      const segs: Seg[] = [];
      let acc = -(f[0] + f[1] + f[2] / 2); // Anteil am linken Bar-Rand
      for (let i = 0; i < 5; i++) {
        if (f[i] > 0)
          segs.push({
            i,
            x: XC + acc * HALF + GAP / 2,
            w: Math.max(1, f[i] * HALF - GAP),
          });
        acc += f[i];
      }
      return { node, n, mean, segs };
    });
    // Leaderboard: nach mittlerer Position; unbewertete ans Ende.
    return built.sort((a, b) => {
      if (a.n === 0 || b.n === 0) return a.n === 0 ? (b.n === 0 ? 0 : 1) : -1;
      return b.mean - a.mean;
    });
  }, [nodes]);

  if (!nodes.length) return null;

  const rowGrid =
    "grid grid-cols-[minmax(120px,200px)_1fr_auto] items-center gap-3";

  return (
    <Card className="border-black/5 py-5">
      <CardContent className="px-4">
        <p className="mb-0.5 text-sm font-medium text-foreground/90">
          {t("cloudTitle")}
        </p>
        <p className="mb-3 text-[13px] leading-snug text-muted-foreground">
          {t("cloudSubtitle")}
        </p>

        {/* Legende der fünf Stufen */}
        <div className="mb-3 flex flex-wrap items-center justify-center gap-x-4 gap-y-1 text-xs text-muted-foreground">
          {CATS.map((cat) => (
            <span key={cat.key} className="inline-flex items-center gap-1.5">
              <span
                className="h-2.5 w-2.5 rounded-[3px]"
                style={{ background: cat.color }}
              />
              {t(cat.label)}
            </span>
          ))}
        </div>

        <div className="flex flex-col gap-1.5">
          {rows.map(({ node, n, mean, segs }) => {
            const badge = n === 0 ? ZERO : mean > 0 ? POS : mean < 0 ? NEG : ZERO;
            return (
              <div key={node.id} className={rowGrid}>
                <span
                  className="truncate text-left text-sm text-foreground/80"
                  title={node.name}
                >
                  {node.name}
                </span>

                <svg
                  viewBox={`0 0 ${VW} ${BARH}`}
                  className="block h-auto w-full"
                  role="img"
                  aria-label={`${node.name} · n=${n} · ${signed(mean)}`}
                >
                  {/* Schiene */}
                  <rect
                    x={X0}
                    y={TRACK_Y}
                    width={X1 - X0}
                    height={TRACK_H}
                    rx={TRACK_H / 2}
                    fill="rgba(0,0,0,0.04)"
                  />
                  {/* neutrale Mitte */}
                  <line
                    x1={XC}
                    y1={1}
                    x2={XC}
                    y2={BARH - 1}
                    stroke="var(--line-mid)"
                    strokeWidth={0.6}
                    strokeDasharray="3 3"
                  />
                  {/* Pill-Segmente */}
                  {n > 0 ? (
                    segs.map((s) => (
                      <rect
                        key={s.i}
                        x={s.x}
                        y={BAR_Y}
                        width={s.w}
                        height={BAR_H}
                        rx={BAR_H / 2}
                        fill={CATS[s.i].color}
                      >
                        <title>{`${t(CATS[s.i].label)}`}</title>
                      </rect>
                    ))
                  ) : (
                    <circle
                      cx={XC}
                      cy={BARH / 2}
                      r={3}
                      fill="var(--line-mid)"
                    />
                  )}
                </svg>

                <span
                  className="justify-self-end rounded-md px-1.5 py-0.5 text-xs font-semibold tabular-nums"
                  style={{ background: badge.bg, color: badge.fg }}
                  title={n === 0 ? t("unrated") : undefined}
                >
                  {n === 0 ? "—" : signed(mean)}
                </span>
              </div>
            );
          })}
        </div>

        {/* Pol-Beschriftung: mehr Nein ← neutral → mehr Ja */}
        <div className={`${rowGrid} mt-2`}>
          <span />
          <div className="flex justify-between text-xs font-medium text-muted-foreground">
            <span>← {t("cloudMoreNo")}</span>
            <span>{t("neutral")}</span>
            <span>{t("cloudMoreYes")} →</span>
          </div>
          <span />
        </div>
      </CardContent>
    </Card>
  );
}

export default PositionCloud;
